const topic = $.input.topic;
const count = parseInt($.input.videoCount || '5', 10);
const style = $.input.channelStyle || 'educational and engaging';
const date = new Date().toISOString().split('T')[0];

let prompt = 'You are a YouTube content strategist and SEO expert. Generate a batch of video concepts with full production details for a channel focused on the given topic.\n\n';
prompt += 'TOPIC: ' + topic + '\n';
prompt += 'NUMBER OF VIDEOS: ' + count + '\n';
prompt += 'CHANNEL STYLE: ' + style + '\n\n';
prompt += 'For each video, provide a complete production plan optimized for YouTube discovery and viewer retention. Return ONLY valid JSON.\n\n';
prompt += 'Return this exact structure:\n';
prompt += '{\n';
prompt += '  "channelStrategy": "1-2 sentence overall channel positioning advice",\n';
prompt += '  "videos": [\n';
prompt += '    {\n';
prompt += '      "title": "SEO-optimized YouTube title (60 chars max, include power words)",\n';
prompt += '      "description": "YouTube description (first 2 lines are most important, include keywords)",\n';
prompt += '      "tags": ["relevant", "youtube", "tags"],\n';
prompt += '      "thumbnailIdea": "detailed thumbnail concept (text overlay, imagery, colors)",\n';
prompt += '      "hook": "first 30 seconds script to maximize retention",\n';
prompt += '      "outline": [\n';
prompt += '        { "timestamp": "0:00", "section": "section name", "content": "what to cover", "duration": "estimated minutes" }\n';
prompt += '      ],\n';
prompt += '      "fullScript": "complete narration script with section markers",\n';
prompt += '      "bRoll": ["b-roll footage suggestions"],\n';
prompt += '      "estimatedLength": "total video length",\n';
prompt += '      "targetKeywords": ["primary keyword", "secondary keywords"],\n';
prompt += '      "competitiveAngle": "what makes this different from existing videos on this topic",\n';
prompt += '      "endScreen": "end screen CTA and suggested next video"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "publishingSchedule": "recommended order and timing for publishing these videos",\n';
prompt += '  "playlistSuggestion": "playlist name and organization"\n';
prompt += '}\n';

return { prompt, date, topic };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { videos: [], channelStrategy: '', text: raw }; }

const ai = $.steps.parseAI.output;
const date = $.steps.buildPrompt.output.date;
const videos = ai.videos || [];

const sheetData = videos.map((v, i) => ({
  '#': i + 1,
  'Title': v.title || '',
  'Est. Length': v.estimatedLength || '',
  'Primary Keyword': (v.targetKeywords || [])[0] || '',
  'Tags': (v.tags || []).join(', '),
  'Thumbnail Idea': v.thumbnailIdea || '',
  'Hook (first 30s)': (v.hook || '').slice(0, 300),
  'Competitive Angle': v.competitiveAngle || '',
  'Sections': (v.outline || []).map(o => o.section).join(' > '),
  'Status': 'Planned',
  'Date Created': date
}));

return { sheetData, videoCount: videos.length };

const ai = $.steps.parseAI.output;
const topic = $.steps.buildPrompt.output.topic;
const date = $.steps.buildPrompt.output.date;
const videos = ai.videos || [];

let doc = 'VIDEO CONTENT PLAN: ' + topic + '\n';
doc += '='.repeat(50) + '\n';
doc += 'Generated: ' + date + '\n';
doc += 'Videos: ' + videos.length + '\n';
if (ai.channelStrategy) doc += 'Strategy: ' + ai.channelStrategy + '\n';
doc += '\n';

videos.forEach((v, i) => {
  doc += '-'.repeat(50) + '\n';
  doc += 'VIDEO ' + (i + 1) + ': ' + (v.title || 'Untitled') + '\n';
  doc += '-'.repeat(50) + '\n\n';

  if (v.description) {
    doc += 'DESCRIPTION:\n' + v.description + '\n\n';
  }
  if (v.targetKeywords && v.targetKeywords.length) {
    doc += 'KEYWORDS: ' + v.targetKeywords.join(', ') + '\n';
  }
  if (v.tags && v.tags.length) {
    doc += 'TAGS: ' + v.tags.join(', ') + '\n';
  }
  if (v.thumbnailIdea) {
    doc += 'THUMBNAIL: ' + v.thumbnailIdea + '\n';
  }
  if (v.estimatedLength) {
    doc += 'LENGTH: ' + v.estimatedLength + '\n';
  }
  if (v.competitiveAngle) {
    doc += 'ANGLE: ' + v.competitiveAngle + '\n';
  }
  doc += '\n';

  if (v.outline && v.outline.length) {
    doc += 'OUTLINE:\n';
    v.outline.forEach(o => {
      doc += '  [' + (o.timestamp || '') + '] ' + (o.section || '') + ' (' + (o.duration || '') + ')\n';
      doc += '    ' + (o.content || '') + '\n';
    });
    doc += '\n';
  }

  if (v.hook) {
    doc += 'HOOK (First 30 seconds):\n' + v.hook + '\n\n';
  }

  if (v.fullScript) {
    doc += 'FULL SCRIPT:\n' + v.fullScript + '\n\n';
  }

  if (v.bRoll && v.bRoll.length) {
    doc += 'B-ROLL SUGGESTIONS:\n';
    v.bRoll.forEach(b => { doc += '  - ' + b + '\n'; });
    doc += '\n';
  }

  if (v.endScreen) {
    doc += 'END SCREEN: ' + v.endScreen + '\n';
  }
  doc += '\n\n';
});

if (ai.publishingSchedule) {
  doc += 'PUBLISHING SCHEDULE:\n' + ai.publishingSchedule + '\n\n';
}
if (ai.playlistSuggestion) {
  doc += 'PLAYLIST: ' + ai.playlistSuggestion + '\n';
}

return { content: doc, title: 'Video Plan - ' + topic };
